const item = $input.first();
const binary = item.binary || {};
const imageKey = Object.keys(binary).find((key) => binary[key]?.mimeType?.startsWith('image/'));
if (!imageKey) {
  throw new Error('No image binary found in webhook payload');
}
const image = binary[imageKey];
return [{
  json: {
    imageKey,
    mimeType: image.mimeType || 'image/jpeg'
  },
  binary: item.binary
}];

const item = $input.first();
const imageKey = item.json.imageKey;
const image = item.binary?.[imageKey];
const base64 = image?.data;
if (!base64) {
  throw new Error('Image payload is empty');
}
const prompt = `You are a librarian cataloguing system. Analyze the uploaded book cover image. Return ONLY valid JSON with this shape: {\n  "isbn": null,\n  "title": null,\n  "author": null,\n  "publisher": null,\n  "category": null\n}`;
return [{
  json: {
    contents: [{
      role: 'user',
      parts: [
        { text: prompt },
        {
          inline_data: {
            mime_type: item.json.mimeType || 'image/jpeg',
            data: base64
          }
        }
      ]
    }]
  }
}];

const body = $input.first().json;
const text = body?.candidates?.[0]?.content?.parts?.[0]?.text || '';
let parsed = {};
const clean = text.replace(/```json\n?|```/g, '').trim();
try {
  parsed = JSON.parse(clean);
} catch (error) {
  const match = clean.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  }
}
const title = typeof parsed.title === 'string' ? parsed.title.trim() : null;
const author = typeof parsed.author === 'string' ? parsed.author.trim() : null;
const isbn = typeof parsed.isbn === 'string' ? parsed.isbn.replace(/[^0-9Xx]/g, '') : null;
const queryTitle = title ? `intitle:${title}` : null;
const googleUrl = isbn
  ? `https://www.googleapis.com/books/v1/volumes?q=isbn:${isbn}`
  : (queryTitle ? `https://www.googleapis.com/books/v1/volumes?q=${encodeURIComponent(queryTitle + (author ? ' inauthor:' + author : ''))}&maxResults=3` : null);
const openLibraryUrl = isbn
  ? `https://openlibrary.org/isbn/${isbn}.json`
  : (title ? `https://openlibrary.org/search.json?title=${encodeURIComponent(title)}${author ? `&author=${encodeURIComponent(author)}` : ''}&limit=1` : null);
const websearchQuery = title
  ? `Buku ${title}${author ? ' ' + author : ''} site:gramedia.com OR site:gramedia.digital`
  : null;
return [{
  json: {
    gemini: parsed,
    googleUrl,
    openLibraryUrl,
    websearchQuery
  }
}];

const entries = $input.all().map((item) => item.json || {});
const root = entries.find((entry) => entry.gemini) || {};
const gemini = root.gemini || {};
const googleRaw = entries.find((entry) => Array.isArray(entry.items));
const openLibraryRaw = entries.find((entry) => entry.title || entry.publishers || Array.isArray(entry.docs));
const tavilyRaw = entries.find((entry) => Array.isArray(entry.results));

let google = {};
if (googleRaw?.items?.length) {
  const info = googleRaw.items[0]?.volumeInfo || {};
  let isbn = null;
  for (const identifier of info.industryIdentifiers || []) {
    if (identifier?.identifier) {
      isbn = String(identifier.identifier).replace(/[^0-9Xx]/g, '');
      if ((identifier.type || '').toUpperCase() === 'ISBN_13') break;
    }
  }
  google = {
    title: info.title || null,
    author: Array.isArray(info.authors) ? info.authors.join(', ') : null,
    isbn,
    publisher: info.publisher || null,
    published_year: info.publishedDate ? parseInt(String(info.publishedDate).substring(0, 4), 10) : null,
    description: info.description || null,
    category: Array.isArray(info.categories) ? info.categories[0] : null,
    cover_url: info.imageLinks?.thumbnail ? String(info.imageLinks.thumbnail).replace('http://', 'https://') : null,
    source: 'google'
  };
}

let openLibrary = {};
if (Array.isArray(openLibraryRaw?.docs) && openLibraryRaw.docs.length) {
  const doc = openLibraryRaw.docs[0];
  openLibrary = {
    title: doc.title || null,
    author: Array.isArray(doc.author_name) ? doc.author_name.join(', ') : null,
    isbn: Array.isArray(doc.isbn) ? String(doc.isbn[0]).replace(/[^0-9Xx]/g, '') : null,
    publisher: Array.isArray(doc.publisher) ? doc.publisher[0] : null,
    published_year: doc.first_publish_year || null,
    description: null,
    category: Array.isArray(doc.subject) ? doc.subject[0] : null,
    cover_url: doc.cover_i ? `https://covers.openlibrary.org/b/id/${doc.cover_i}-M.jpg` : null,
    source: 'openlibrary'
  };
} else if (openLibraryRaw?.title) {
  openLibrary = {
    title: openLibraryRaw.title || null,
    author: Array.isArray(openLibraryRaw.authors) ? openLibraryRaw.authors.map((entry) => entry?.name || entry).join(', ') : null,
    isbn: Array.isArray(openLibraryRaw.isbn_13) ? String(openLibraryRaw.isbn_13[0]).replace(/[^0-9Xx]/g, '') : (gemini.isbn || null),
    publisher: Array.isArray(openLibraryRaw.publishers) ? openLibraryRaw.publishers[0] : null,
    published_year: openLibraryRaw.publish_date || null,
    description: typeof openLibraryRaw.description === 'string' ? openLibraryRaw.description : openLibraryRaw.description?.value || null,
    category: null,
    cover_url: Array.isArray(openLibraryRaw.covers) && openLibraryRaw.covers[0] ? `https://covers.openlibrary.org/b/id/${openLibraryRaw.covers[0]}-M.jpg` : null,
    source: 'openlibrary'
  };
}

let websearch = {};
if (Array.isArray(tavilyRaw?.results) && tavilyRaw.results.length) {
  const top = tavilyRaw.results[0];
  websearch = {
    description: top.content || null,
    source_url: top.url || null,
    source: 'websearch'
  };
}

const pick = (...values) => values.find((value) => value !== null && value !== undefined && value !== '') || null;
const book = {
  title: pick(google.title, openLibrary.title, gemini.title),
  author: pick(google.author, openLibrary.author, gemini.author),
  isbn: pick(google.isbn, openLibrary.isbn, gemini.isbn),
  publisher: pick(google.publisher, openLibrary.publisher, gemini.publisher),
  published_year: pick(google.published_year, openLibrary.published_year, null),
  description: pick(google.description, openLibrary.description, websearch.description, null),
  category: pick(google.category, openLibrary.category, gemini.category),
  cover_url: pick(google.cover_url, openLibrary.cover_url, null),
  source_url: pick(websearch.source_url, null)
};
const hasCoreData = Boolean(book.title || book.author || book.isbn);
return [{
  json: {
    found: hasCoreData,
    source: book.description && !google.description && !openLibrary.description ? 'websearch' : (google.title || google.isbn ? 'google' : (openLibrary.title || openLibrary.isbn ? 'openlibrary' : 'gemini')),
    book,
    sources_used: {
      gemini_vision: true,
      google_books: Boolean(google.title || google.isbn),
      openlibrary: Boolean(openLibrary.title || openLibrary.isbn),
      websearch: Boolean(websearch.description)
    }
  }
}];
